function S(n,o=20,t=5){if(!n||n.length<=o)return n;if(o<=t+3)return"..."+n.slice(-t);const i=Array.from(n);if(i.length<=o)return n;const r=o-t-3,c=i.slice(0,r).join(""),I=i.slice(-t).join("");return c+"..."+I}function s(n,o="long",t="en-US"){const e={month:o==="short"?"short":"long",...o!=="monthyear"&&{day:"numeric"},...o!=="short"&&{year:"numeric"}};return new Intl.DateTimeFormat(t,e).format(n)}export{s as f,S as t};
